import{_ as a,c as s,o as e,a2 as n}from"./chunks/framework.DSS9r8Op.js";const b=JSON.parse('{"title":"PHP 配置流程","description":"","frontmatter":{},"headers":[],"relativePath":"code/basic/php.md","filePath":"code/basic/php.md"}'),p={name:"code/basic/php.md"},i=n(`<h1 id="php-配置流程" tabindex="-1">PHP 配置流程 <a class="header-anchor" href="#php-配置流程" aria-label="Permalink to &quot;PHP 配置流程&quot;">​</a></h1><h2 id="_1-ubuntu-下配置-php" tabindex="-1">1. Ubuntu 下配置 PHP <a class="header-anchor" href="#_1-ubuntu-下配置-php" aria-label="Permalink to &quot;1. Ubuntu 下配置 PHP&quot;">​</a></h2><h3 id="_1-1-更新-apt" tabindex="-1">1.1 更新 apt <a class="header-anchor" href="#_1-1-更新-apt" aria-label="Permalink to &quot;1.1 更新 apt&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>sudo apt update</span></span></code></pre></div><h3 id="_1-2-添加-php-ppa" tabindex="-1">1.2 添加 PHP PPA <a class="header-anchor" href="#_1-2-添加-php-ppa" aria-label="Permalink to &quot;1.2 添加 PHP PPA&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>sudo add-apt-repository ppa:ondrej/php</span></span>
<span class="line"><span>sudo apt update</span></span></code></pre></div><h3 id="_1-3-安装指定版本的-php" tabindex="-1">1.3 安装指定版本的 PHP <a class="header-anchor" href="#_1-3-安装指定版本的-php" aria-label="Permalink to &quot;1.3 安装指定版本的 PHP&quot;">​</a></h3><p>此处是以 <code>PHP7.4</code> 为例，如果环境中需要用 <code>nginx</code> 作为服务器，还需要下载 <code>php-fpm</code> 扩展</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>sudo apt install php7.4</span></span>
<span class="line"><span>sudo apt install php7.4-fpm</span></span>
<span class="line"><span>sudo apt install php7.4-{dev,mysql,curl,json,mbstring,xml,intl,yaml,zip}</span></span></code></pre></div><h2 id="_2-在-ubuntu-下切换-php-版本" tabindex="-1">2. 在 Ubuntu 下切换 PHP 版本 <a class="header-anchor" href="#_2-在-ubuntu-下切换-php-版本" aria-label="Permalink to &quot;2. 在 Ubuntu 下切换 PHP 版本&quot;">​</a></h2><p>或许安装了很多个 <code>PHP</code> ，难免会遇到切换版本的时候</p><h3 id="_2-1-使用-update-alternatives-工具管理-php" tabindex="-1">2.1 使用 update-alternatives 工具管理 PHP <a class="header-anchor" href="#_2-1-使用-update-alternatives-工具管理-php" aria-label="Permalink to &quot;2.1 使用 update-alternatives 工具管理 PHP&quot;">​</a></h3><p>执行 <code>sudo update-alternatives --config php</code> ，这个命令会列出所有安装的 <code>PHP</code> 版本，并允许你选择默认的命令行版本</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>There are 3 choices for the alternative php (providing /usr/bin/php).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Selection    Path             Priority   Status</span></span>
<span class="line"><span>------------------------------------------------------------</span></span>
<span class="line"><span>  0            /usr/bin/php8.3   83        auto mode</span></span>
<span class="line"><span>* 1            /usr/bin/php7.4   74        manual mode</span></span>
<span class="line"><span>  2            /usr/bin/php8.1   81        manual mode</span></span>
<span class="line"><span>  3            /usr/bin/php8.3   83        manual mode</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Press &lt;enter&gt; to keep the current choice[*], or type selection number:</span></span></code></pre></div><p>如果你想切换到 <code>PHP8.1</code>，那么输入 2，然后回车。 你可能还需要更新 <code>Apache</code> 或 <code>nginx</code>（如果你使用这些web服务器的话）来使用新版本的PHP。</p><h3 id="_2-2-apache-配置" tabindex="-1">2.2 Apache 配置 <a class="header-anchor" href="#_2-2-apache-配置" aria-label="Permalink to &quot;2.2 Apache 配置&quot;">​</a></h3><p>对于 <code>Apache</code>，你可以禁用旧版本的 <code>PHP module</code>，并启用你想要使用的版本：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>sudo a2dismod php7.4  # 禁用PHP 7.4</span></span>
<span class="line"><span>sudo a2enmod php8.1   # 启用PHP 8.1</span></span>
<span class="line"><span>sudo service apache2 restart</span></span></code></pre></div><h3 id="_2-3-nginx-配置" tabindex="-1">2.3 Nginx 配置 <a class="header-anchor" href="#_2-3-nginx-配置" aria-label="Permalink to &quot;2.3 Nginx 配置&quot;">​</a></h3><p>对于 <code>nginx</code> ，你需要编辑你的 <code>nginx</code> 配置文件，通常位于 <code>/etc/nginx/sites-available/</code> 中，然后重启nginx服务：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span># 编辑对应的nginx配置文件，更新fastcgi_pass指向到新的PHP FPM socket</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sudo service nginx restart</span></span></code></pre></div><h2 id="_3-使用-php-中遇到的一些问题" tabindex="-1">3. 使用 PHP 中遇到的一些问题 <a class="header-anchor" href="#_3-使用-php-中遇到的一些问题" aria-label="Permalink to &quot;3. 使用 PHP 中遇到的一些问题&quot;">​</a></h2><h3 id="_3-1-form-表单提交过多-php-无法处理" tabindex="-1">3.1 Form 表单提交过多 PHP 无法处理 <a class="header-anchor" href="#_3-1-form-表单提交过多-php-无法处理" aria-label="Permalink to &quot;3.1 Form 表单提交过多 PHP 无法处理&quot;">​</a></h3><p>自从 <code>PHP5.3</code> 之后，最多接收 1000 项 <code>form</code> 表单的数据，这个参数可以在 <code>php.ini</code> 里调整</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>max_input_var = 2000</span></span></code></pre></div><h3 id="_3-2-上传文件大小限制" tabindex="-1">3.2 上传文件大小限制 <a class="header-anchor" href="#_3-2-上传文件大小限制" aria-label="Permalink to &quot;3.2 上传文件大小限制&quot;">​</a></h3><p><code>php.ini</code> 中有默认的上传文件大小限制，可能不足以完成业务需求，注意 <code>post_max_size</code> 包含了文件，所以应该 <code>post_max_size</code> &gt; <code>upload_max_filesize</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>file_uploads = on ;       // 是否允许上传，默认为ON</span></span>
<span class="line"><span>upload_max_filesize = 2m; // 允许上传文件大小的最大值</span></span>
<span class="line"><span>post_max_size = 8m ;      // 指通过表单 POST 给 PHP 的所能接收的最大值，包括文件</span></span>
<span class="line"><span>max_execution_time = 600; // PHP 页面运行的最大时间值(秒)，默认 30 秒</span></span>
<span class="line"><span>max_input_time = 600;     // PHP 页面接收数据所需的最大时间，默认 60 秒</span></span>
<span class="line"><span>memory_limit = 8m ;       // 每个 PHP 页面所吃掉的最大内存</span></span></code></pre></div><p>如果使用了 <code>nginx</code> 反向代理，需要在对应的配置中加入 <code>client_max_body_size</code> 参数</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>server</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>    listen 80;</span></span>
<span class="line"><span>    client_max_body_size 10m;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    其他配置</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,30),t=[i];function o(l,c,d,h,r,u){return e(),s("div",null,t)}const m=a(p,[["render",o]]);export{b as __pageData,m as default};
